// JSON-RPC 2.0 — the message format used by ALL MCP transports

// 1. Client request (tools/call):
const request = {
  "jsonrpc": "2.0",
  "id": 42,              // numeric or string ID — correlates response to request
  "method": "tools/call",
  "params": {
    "name": "search_customers",
    "arguments": { "query": "Acme Corp", "limit": 10 }
  }
};

// 2. Successful response:
const success = {
  "jsonrpc": "2.0",
  "id": 42,              // echoes the request ID
  "result": {
    "content": [{ "type": "text", "text": "[{\"id\":123,\"name\":\"Acme Corp\"}]" }],
    "isError": false
  }
};

// 3. Error response (protocol-level error, e.g., method not found):
const protocolError = {
  "jsonrpc": "2.0",
  "id": 42,
  "error": {
    "code": -32601,      // -32600 = Invalid Request, -32601 = Method not found
    "message": "Method not found",
    "data": { "method": "tools/call" }
  }
};

// 4. Notification (no ID — no response expected):
const notification = {
  "jsonrpc": "2.0",      // no "id" field = this is a notification
  "method": "notifications/tools/list_changed",
  "params": {}
};
